                  repo.parentBranch = parent;
                  repo.branch = br.branch;
                  fileLog(`git: end-of-task auto-branch ${br.branch} on ${nodePath.relative(session.activeProject, repoDir) || '.'} (clean at open, dirtied via non-write_file path)`);
